from pagination import Paginator


def render_list(data, page_num, page_size=10):
    p = Paginator(data, page_size=page_size)
    page = p.get_page(page_num)
    result = {"items": page.items, "has_next": page.has_next, "has_prev": page.has_prev}
    return result


def render_all_pages(data, page_size=5):
    p = Paginator(data, page_size)
    return [page.to_dict() for page in p]

