from pagination import Paginator


def export_all(data, chunk_size=100):
    all_items = []
    for page in Paginator(data, page_size=chunk_size):
        all_items.extend(page.items)
    return all_items


def count_pages(data, chunk_size=100):
    p = Paginator(data, chunk_size)
    page = p.get_page(1)
    return page.total_pages
